import{_ as a,o as d,c as e,ag as r}from"./chunks/framework.CQYuu_FX.js";const p=JSON.parse('{"title":"ログインとアカウント","description":"","frontmatter":{"title":"ログインとアカウント"},"headers":[],"relativePath":"tenant/02-login.md","filePath":"tenant/02-login.md"}'),l={name:"tenant/02-login.md"};function i(h,t,o,n,s,b){return d(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="_2-ログインとアカウント" tabindex="-1">2. ログインとアカウント <a class="header-anchor" href="#_2-ログインとアカウント" aria-label="Permalink to &quot;2. ログインとアカウント&quot;">​</a></h1><p>この章では、POSLAへのログイン、パスワード変更、スタッフアカウント、端末専用アカウントの扱いを説明します。</p><h2 id="ログイン方法" tabindex="-1">ログイン方法 <a class="header-anchor" href="#ログイン方法" aria-label="Permalink to &quot;ログイン方法&quot;">​</a></h2><ol><li>POSLAのログイン画面を開きます。</li><li>ユーザー名とパスワードを入力します。</li><li>「ログイン」を押します。</li><li>ロールに応じた管理画面が表示されます。</li></ol><p>メールアドレスは必須ではありません。店舗内で管理しやすいユーザー名を使ってください。</p><h2 id="パスワードの管理" tabindex="-1">パスワードの管理 <a class="header-anchor" href="#パスワードの管理" aria-label="Permalink to &quot;パスワードの管理&quot;">​</a></h2><ul><li>パスワードは8文字以上で、英字と数字を含めてください。</li><li>初期パスワードは、初回ログイン後に本人が変更する運用を推奨します。</li><li>パスワードを忘れたスタッフは、オーナーまたはマネージャーに再設定を依頼してください。</li><li>オーナーがログインできない場合は、POSLAサポートへお問い合わせください。</li></ul><h2 id="_1人1アカウントのルール" tabindex="-1">1人1アカウントのルール <a class="header-anchor" href="#_1人1アカウントのルール" aria-label="Permalink to &quot;1人1アカウントのルール&quot;">​</a></h2><p>POSLAでは、スタッフごとに個別アカウントを作成してください。共有アカウントは使用しないでください。</p><table tabindex="0"><thead><tr><th>理由</th><th>説明</th></tr></thead><tbody><tr><td>勤怠管理</td><td>出勤・退勤を個人ごとに記録するため</td></tr><tr><td>会計操作</td><td>返金や現金操作の担当者を明確にするため</td></tr><tr><td>監査ログ</td><td>いつ誰が操作したかを確認できるようにするため</td></tr><tr><td>シフト管理</td><td>希望提出や実績集計を個人単位で行うため</td></tr></tbody></table><h2 id="アカウント作成権限" tabindex="-1">アカウント作成権限 <a class="header-anchor" href="#アカウント作成権限" aria-label="Permalink to &quot;アカウント作成権限&quot;">​</a></h2><table tabindex="0"><thead><tr><th>操作者</th><th>作成できるアカウント</th><th>対象範囲</th></tr></thead><tbody><tr><td>オーナー</td><td>マネージャー、スタッフ、端末専用アカウント</td><td>全店舗</td></tr><tr><td>マネージャー</td><td>スタッフ、端末専用アカウント</td><td>自分の所属店舗</td></tr><tr><td>スタッフ</td><td>作成不可</td><td>なし</td></tr></tbody></table><h2 id="端末専用アカウント" tabindex="-1">端末専用アカウント <a class="header-anchor" href="#端末専用アカウント" aria-label="Permalink to &quot;端末専用アカウント&quot;">​</a></h2><p>KDS、POSレジ、ハンディなどの店舗備品には、端末専用アカウントを使用します。端末専用アカウントは人ではなく機器を表すため、シフト、勤怠、人件費、スタッフ評価の対象にはなりません。</p><h2 id="pinについて" tabindex="-1">PINについて <a class="header-anchor" href="#pinについて" aria-label="Permalink to &quot;PINについて&quot;">​</a></h2><p>POSレジでの会計、返金、レジ開け、レジ閉め、現金入金、現金出金では、担当スタッフのPIN入力が必要です。PINにより、端末専用アカウントでログインしている場合でも、実際に操作したスタッフを記録できます。</p><h2 id="セッションとログアウト" tabindex="-1">セッションとログアウト <a class="header-anchor" href="#セッションとログアウト" aria-label="Permalink to &quot;セッションとログアウト&quot;">​</a></h2><p>管理画面を使う共有PCでは、作業終了後にログアウトしてください。スタッフ個人アカウントを共有PCに残したままにしないためです。</p><p>KDS、POSレジ、ハンディの店舗備品端末は、端末専用アカウントで常時ログインしておく運用です。日次閉店時はログアウトではなく、画面ロック、充電、通知音、翌日使う端末モードを確認してください。端末を紛失した、端末を入れ替える、店舗から外す場合は、対象の端末専用アカウントを無効化またはパスワード変更してください。</p><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>ログインできない</td><td>ユーザー名、パスワード、半角全角、Caps Lockを確認してください。</td></tr><tr><td>パスワードを忘れた</td><td>上司に再設定を依頼してください。</td></tr><tr><td>画面が真っ白になる</td><td>ブラウザを再読み込みしてください。改善しない場合は別端末でお試しください。</td></tr><tr><td>権限が不足している</td><td>オーナーまたはマネージャーに権限を確認してください。</td></tr></tbody></table>',21)])])}const P=a(l,[["render",i]]);export{p as __pageData,P as default};
